        if (time + 1 < dist[node]) {
            dist[node] = time + 1;
            pq.push({time + 1, node});
        }

        // Check all outgoing edges
        for (const auto& edge : graph[node]) {
            long long v = edge[0];
            long long start = edge[1];
            long long end = edge[2];

            if (time > end) {
                continue;
            }

            long long arrival_time = max(time, start) + 1;
            if (arrival_time < dist[v]) {
                dist[v] = arrival_time;
                pq.push({arrival_time, v});
            }
        }
    }

    return -1;
}

